using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.Logging;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides a web search tool the agent can call to find information online.
/// Uses the Brave Search API (free tier available at https://brave.com/search/api/).
/// </summary>
public sealed class WebSearchTool(HttpClient httpClient, ILogger<WebSearchTool> logger)
{
    [Description("Search the web for a given query and return a list of results with titles, URLs, and snippets.")]
    public async Task<IReadOnlyList<SearchResult>> SearchWebAsync(
        [Description("The search query string")] string query,
        [Description("Maximum number of results to return (1-10)")] int maxResults = 5,
        CancellationToken cancellationToken = default)
    {
        maxResults = Math.Clamp(maxResults, 1, 10);
        logger.LogInformation("Searching the web for: {Query} (max {Max} results)", query, maxResults);

        try
        {
            var url = $"https://api.search.brave.com/res/v1/web/search?q={Uri.EscapeDataString(query)}&count={maxResults}";
            var response = await httpClient.GetAsync(url, cancellationToken);
            response.EnsureSuccessStatusCode();

            var json = await response.Content.ReadFromJsonAsync<JsonElement>(cancellationToken);
            var results = new List<SearchResult>();

            if (json.TryGetProperty("web", out var web) &&
                web.TryGetProperty("results", out var webResults))
            {
                foreach (var item in webResults.EnumerateArray())
                {
                    results.Add(new SearchResult
                    {
                        Title = item.GetProperty("title").GetString() ?? "",
                        Url = item.GetProperty("url").GetString() ?? "",
                        Snippet = item.TryGetProperty("description", out var desc)
                            ? desc.GetString() ?? ""
                            : "",
                    });

                    if (results.Count >= maxResults)
                        break;
                }
            }

            logger.LogInformation("Found {Count} results for: {Query}", results.Count, query);
            return results;
        }
        catch (HttpRequestException ex)
        {
            logger.LogWarning(ex, "Web search failed for query: {Query}", query);
            return [new SearchResult
            {
                Title = "Search unavailable",
                Url = "",
                Snippet = $"Web search failed: {ex.Message}. Try rephrasing the query or using information from your training data.",
            }];
        }
    }
}

public sealed class SearchResult
{
    public required string Title { get; set; }
    public required string Url { get; set; }
    public required string Snippet { get; set; }

    public override string ToString() => $"[{Title}]({Url}): {Snippet}";
}

using System.ComponentModel;
using Microsoft.Extensions.Logging;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides a note-taking tool the agent can use to record findings during research.
/// Notes are stored in memory and can be reviewed before generating the final summary.
/// </summary>
public sealed class NoteTool(ILogger<NoteTool> logger)
{
    private readonly List<Note> _notes = [];

    [Description("Save a research note with a topic tag and content. Use this to record important findings from search results.")]
    public string SaveNote(
        [Description("A short topic tag for the note (e.g., 'key-finding', 'statistic', 'source')")] string topic,
        [Description("The content of the note")] string content)
    {
        var note = new Note
        {
            Id = _notes.Count + 1,
            Topic = topic,
            Content = content,
            Timestamp = DateTime.UtcNow,
        };

        _notes.Add(note);
        logger.LogInformation("Saved note #{Id} [{Topic}]: {Content}",
            note.Id, note.Topic, Truncate(note.Content, 80));

        return $"Note #{note.Id} saved under topic '{topic}'.";
    }

    [Description("Retrieve all saved notes, optionally filtered by topic tag.")]
    public IReadOnlyList<Note> GetNotes(
        [Description("Optional topic tag to filter notes. Leave empty to get all notes.")] string? topic = null)
    {
        var results = string.IsNullOrWhiteSpace(topic)
            ? _notes
            : _notes.Where(n => n.Topic.Contains(topic, StringComparison.OrdinalIgnoreCase)).ToList();

        logger.LogInformation("Retrieved {Count} notes{Filter}",
            results.Count,
            string.IsNullOrWhiteSpace(topic) ? "" : $" filtered by '{topic}'");

        return results;
    }

    private static string Truncate(string text, int maxLength) =>
        text.Length <= maxLength ? text : string.Concat(text.AsSpan(0, maxLength), "...");
}

public sealed class Note
{
    public int Id { get; set; }
    public required string Topic { get; set; }
    public required string Content { get; set; }
    public DateTime Timestamp { get; set; }

    public override string ToString() => $"[#{Id} {Topic}] {Content}";
}

