using System.Net.Http.Headers;
using Microsoft.Agents.AI;
using Microsoft.Agents.AI.ChatCompletion;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using OpenAI;
using ResearchAgent.Tools;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable. " +
        "Optionally set BRAVE_API_KEY for web search (free at https://brave.com/search/api/).");

var braveApiKey = Environment.GetEnvironmentVariable("BRAVE_API_KEY");
var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// --- DI Setup ---
var services = new ServiceCollection();

services.AddLogging(builder => builder
    .AddConsole()
    .SetMinimumLevel(LogLevel.Information));

services.AddHttpClient<WebSearchTool>(client =>
{
    if (!string.IsNullOrEmpty(braveApiKey))
    {
        client.DefaultRequestHeaders.Add("X-Subscription-Token", braveApiKey);
        client.DefaultRequestHeaders.Accept.Add(new MediaTypeWithQualityHeaderValue("application/json"));
    }
});

services.AddSingleton<NoteTool>();

services.AddChatClient(builder => builder
    .UseLogging()
    .Use(new OpenAIClient(apiKey).AsChatClient(modelId)));

var provider = services.BuildServiceProvider();

// --- Resolve services ---
var chatClient = provider.GetRequiredService<IChatClient>();
var searchTool = provider.GetRequiredService<WebSearchTool>();
var noteTool = provider.GetRequiredService<NoteTool>();
var logger = provider.GetRequiredService<ILogger<Program>>();

// --- Define agent tools ---
var tools = new AITool[]
{
    AIFunctionFactory.Create(searchTool.SearchWebAsync),
    AIFunctionFactory.Create(noteTool.SaveNote),
    AIFunctionFactory.Create(noteTool.GetNotes),
};

// --- Create the agent ---
var agent = new ChatClientAgent(chatClient, tools)
{
    Name = "ResearchAgent",
    Description = "An AI research assistant that searches the web and takes notes to produce a summary.",
    Instructions = """
        You are a thorough research assistant. When given a topic:
        1. Search the web with 2-3 different queries to gather diverse perspectives.
        2. For each useful finding, save a note with a descriptive topic tag and the key information.
        3. After gathering enough information, retrieve all your notes.
        4. Produce a well-structured summary with:
           - An overview paragraph
           - Key findings as bullet points
           - Sources cited with URLs where available
        Be factual and cite your sources. If search is unavailable, state that clearly.
        """,
};

// --- Get the research topic ---
string topic;
if (args.Length > 0)
{
    topic = string.Join(' ', args);
}
else
